import { CHART_DOMAIN_HELPERS } from '../../../../brush/chart-helpers/domain-helpers';
import { each, getPropVal, setPropVal, splat, defined } from '../../../../utils/zcutils';
import { getAxisObject } from '../../../../axis/axisutils';
import { ORDINAL_DATATYPE } from '../../../../core/datatype-constants';

export function getZoomBound(selection, type) {
    let bound = selection;

    if (type === 'x') {
        bound = [
            [selection[0], 0],
            [selection[1], 0]
        ];
    } else if (type === 'y') {
        bound = [
            [0, selection[0]],
            [0, selection[1]]
        ];
    }

    return bound;
}

/**
 *
 * @param behaviourEventInstance
 * @param selectionManager
 * @param selection
 * @constructor
 */
export function ApplyBrushSelectionOnPlot(behaviourEventInstance, selectionManager, selection) {
    let eventManager = this,
        behaviours = eventManager.behaviours,
        chart = eventManager.chart,
        brushInstance = behaviourEventInstance.instance,
        brushOptions = chart.systemConf.chart.brush,
        domainInfo = selectionManager.point,
        hasSmoothScroll = chart.scroll && chart.scroll.settings.smooth;

    if (!selection) {
        return;
    }

    if (behaviours.PLOT_ZOOM) {
        let bound = getZoomBound(selection, brushInstance.options.type),
            plotZoom = behaviours.PLOT_ZOOM.instance,
            transform = plotZoom.getTransform();

        plotZoom.zoomToBounds(bound.map(b0 => transform.invert(b0)));
    } else {
        // TODO plot brush with scroll smooth
        if (!hasSmoothScroll) {
            saveBrushPosition(domainInfo, brushOptions, chart);
        }
        CHART_DOMAIN_HELPERS.FILTER_CHART(domainInfo, chart);
    }

    // update the plot brush area with the plot area
    // because after applying brush the plot area might change.
    brushInstance.updateExtent([
        [0, 0],
        [chart.plotarea.width, chart.plotarea.height]
    ]);
}

function saveBrushPosition(domainList, settings, chart) {
    each(domainList, (list, type) => {
        each(list, (info, index) => {
            if (info.domain) {
                // #ZC2016
                let axisInfo = getAxisObject(chart, type, index),
                    key = `${type}[${index}]`,
                    z = getPropVal(settings, key),
                    domain = splat(info.domain);

                if (!defined(z)) {
                    setPropVal(settings, key, (z = {}));
                }

                if (info.dataType === ORDINAL_DATATYPE) {
                    z.categories = domain;
                } else {
                    z.minRange = domain[0];
                    z.maxRange = domain[1];
                }
                axisInfo.domain = info.domain || axisInfo.baseScale.domain();
            }
        });
    });
}
